// Test-only manifest: every published noise variant with its full
// NoiseSource, so the parity/chunk/TSL suites can iterate the whole catalog
// without a runtime registry (the registry now lives in the example app).
// Excluded from the build (tsconfig.build.json excludes src/testing).
//
// GENERATED by the restructure and maintained by hand: when a variant is
// added, add its entry here — the bundle test fails if this file ever leaks
// into a consumer bundle.

import * as lib from '../index.js'

import type { NoiseSource } from '../spec.js'

export type VariantEntry = {
  id: string
  /** Lattice cells across one tile at the explorer's default density; the tiling period used by tests. */
  scale: number
  /** How the tileable path relates to the core field (canonical variants only). */
  tileableStrategy?: 'lattice-wrap' | 'torus'
  source: NoiseSource
}

