/** Clamped display sampler over the uniform (x, y, z) shape. */
export const clampedSample = (e: VariantEntry): ((x: number, y: number, z: number) => number) => {
  const s = e.source
  if (s.dim === 2) {
    const f = s.sample
    if (!f) throw new Error(e.id)
    return (x, y) => lib.clamp01(f(x, y))
  }
  const f = s.sample
  if (!f) throw new Error(e.id)
  return (x, y, z) => lib.clamp01(f(x, y, z))
}

/** Clamped tileable sampler over the uniform (x, y, z, px, py) shape, or null. */
export const clampedSampleTileable = (
  e: VariantEntry,
): ((x: number, y: number, z: number, px: number, py: number) => number) | null => {
  const s = e.source
  if (s.dim === 2) {
    const f = s.sampleTileable
    return f ? (x, y, _z, px, py) => lib.clamp01(f(x, y, px, py)) : null
  }
  const f = s.sampleTileable
  return f ? (x, y, z, px, py) => lib.clamp01(f(x, y, z, px, py)) : null
}
